VALUES
  ('social-worker-moex-08200', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '「在校園中，學業成績不及格接受寬恕教育的學生，將比未接受寬恕教育者，對老師表現較低的敵意」， 這段敘述是一種：', '["研究問題", "理論命題", "概念性假設", "操作性假設"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08201', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '「參與受測必須出於自願，絕不能強制以求」是研究的一項基本倫理，因此告知同意（informed consent） 成為一種必要的程序。所謂告知，不應該包含下列何者？', '["說明研究者的真實身分", "告知基本的施測程序", "說明可能涉及的風險", "說明研究假設的相關訊息"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08202', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '方案評鑑中結合量性和質性方法，似乎已成為一種趨勢，可見諸許多社會福利服務方案的評鑑，下列何者', '["方案有無成效", "方案有無成效的實務過程", "方案面臨困境的改善方 法", "方案的成本效益"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08203', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '當檢定統計量的P值為0.025且小於預定的0.05α值時，下列關於此假設顯著性檢定的敘述正確的是：', '["得以拒斥虛無假設", "無法支持對立假設", "研究結論預定承擔至多5％機率的型I錯誤風險", "統計檢 定力為95％"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08204', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '相關敘述如下：①測量進行愈多次，測量出來的趨勢愈穩定  ②採時間序列設計模式  ③針對目標問題進行', '["基線（baseline）階段，介入之前重複測量的階段，類似控制組  ⑤介入階段類似實驗組  介 入前後若有改變即是介入之影響  不可能有巧合發生。請問上列的敘述，指的是那一種研究設計模式？", "拆解性研究設計", "分裂效果研究設計", "單案研究設計"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08205', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '當研究者欲使用存檔資料或次級資料（secondary data），例如全國性之兒童生活狀況調查資料進行研究', '["變項定義之吻合程度", "該資料之效度", "該資料之信度", "該資料中研究變項 之缺漏值  ⑤該資料之涵蓋地區範圍"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08206', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '針對非主流社群，測量程序往往存在文化偏誤（cultural bias）的情形，下列何者是其中普遍且重要的原', '["語言問題", "文化獨特價值", "生活方式", "不合作  ⑤機會不足"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08207', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在進行方案評估時，執行評估的研究者可以是內部人員或外聘專家，而機構主管在選擇執行人員的身分時，', '["計畫經費之要求", "主管之偏好", "過去之慣例", "優缺點之平衡  ⑤方 案服務之特殊性"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08208', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '源自於實驗，指自變項是否如宣稱的那樣對依變項產生影響，而非來自其他變項的影響，稱為：', '["內容效度", "預測效度", "內在效度", "建構效度"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08209', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關社會工作機構對實務工作的影響因素，何者是正確的？', '["公營機構的運作只要是對案主有利的，不應顧慮私人的情感因素", "公營機構財源來自全民，因此效果不彰的案主服務工作應停止", "民營機構不須對政府負責任，因此不必進行評估或研究工作", "民營機構財源來自私人單位，因此不必考慮責信（accountability）問題"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
